INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8551a49c-f983-4a46-ad50-c9e06a796573', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8551a49c-f983-4a46-ad50-c9e06a796573', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8551a49c-f983-4a46-ad50-c9e06a796573', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$AI Content Detector$q$, $q$Scans text for signals of AI-generated writing, drawing on detection models trained against outputs from GPT-4, GPT-4o, Claude, Gemini, Llama, and other large language models, and returns a percentage likelihood score.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Plagiarism Checker$q$, $q$Compares submitted text against indexed web content to surface matching or near-matching passages, run in the same pass as the AI detection check.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Fact-Check (Beta)$q$, $q$Flags specific factual claims within a draft that may warrant a manual verification pass before publishing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Readability Score$q$, $q$Adds a readability assessment alongside AI and plagiarism results so editors can judge overall content quality in one report.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Chrome Extension$q$, $q$Lets writers and editors scan text directly inside Google Docs or on any webpage without leaving the page to run a separate check.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$API Access$q$, $q$Exposes AI detection and plagiarism scanning as an API endpoint so development teams can build checks directly into a CMS or internal publishing workflow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Team Dashboard & Shared Reports$q$, $q$Gives managers visibility into what's been scanned across a team, with reports that can be shared with colleagues without granting full account access.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Scan History$q$, $q$Keeps a searchable record of past scans so teams can review or reference earlier AI and plagiarism checks.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Bulk/Batch Scanning$q$, $q$Supports scanning multiple pieces of content in one pass, useful for agencies or publishers clearing a backlog of freelance submissions.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Detects output from multiple AI models (GPT-4, GPT-4o, Claude, Gemini, Llama) rather than just one$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Combines AI detection and plagiarism checking in a single scan and report$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$API and team dashboard features fit agency and publisher workflows at scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Chrome extension enables in-context scanning of Google Docs and live webpages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Detection models are updated regularly as new AI writing tools emerge$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$No permanent free plan, only a small allotment of free trial credits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Credit-based pricing can become costly for high-volume publishers and agencies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$AI detection accuracy is imperfect on heavily edited or paraphrased text, as with any detector$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Feature set and team pricing are geared toward organizations, which can feel like overkill for a single casual user$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Subscription credits typically expire at the end of each billing cycle if unused$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$What does Originality.ai actually check for?$q$, $q$It checks text for signals of AI-generated writing and for plagiarism against indexed web content, and also offers readability scoring and a beta fact-checking feature.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Is there a free plan?$q$, $q$No. Originality.ai does not offer a permanent free plan; new accounts receive a limited number of free credits to trial the AI and plagiarism detectors before choosing a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$How does the credit-based pricing work?$q$, $q$Every scan consumes credits based on the word count checked. Credits come from a monthly subscription (Pro or Enterprise) or a one-off pay-as-you-go purchase, and subscription credits generally reset each billing cycle.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Which AI models can Originality.ai detect?$q$, $q$It is trained to recognize output from models such as GPT-4, GPT-4o, Claude, Gemini, and Llama, with detection models updated over time as new AI writing tools are released.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$How accurate is the AI detector?$q$, $q$Like all AI content detectors, it is probabilistic rather than certain, and can occasionally return false positives or false negatives, particularly on heavily edited AI text or certain non-native English writing styles.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Editorial quality control for publishers$q$, $q$Screen incoming articles and freelance submissions for AI-generated content and plagiarism before they're published to a live site.$q$, $q$Digital publishers and editorial teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Freelancer content verification for agencies$q$, $q$Check freelance writer deliverables against both AI-detection and plagiarism standards before client delivery, using shared team reports.$q$, $q$Content and marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Protecting SEO content standards$q$, $q$Verify that blog posts and landing pages meet a site's originality and quality bar before they're indexed, protecting organic search performance.$q$, $q$In-house SEO and content marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Academic and institutional integrity checks$q$, $q$Run AI-detection and plagiarism scans on submitted written work as part of a broader academic integrity review process.$q$, $q$Educators and academic institutions$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Pay-As-You-Go$q$, $q$$30 for 3,000 credits$q$, $q$One-time$q$, $q$["Credits purchased upfront with no subscription","Covers combined AI and plagiarism scans","Good fit for occasional or low-volume scanning"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Pro$q$, $q$$14.95/month, or $12.95/month billed annually$q$, $q$Monthly or annual$q$, $q$["2,000 credits per month","Combined AI and plagiarism scanning","Chrome extension access","Shared reports with teammates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$Enterprise$q$, $q$$179/month, or $136.58/month billed annually$q$, $q$Monthly or annual$q$, $q$["15,000 credits per month","API access","Team seats with role-based permissions","Priority support for larger content operations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Originality.ai is an AI content detection and plagiarism checking platform built for publishers, content agencies, and SEO teams that need to verify whether a piece of text was generated by AI or copied from an existing source before it goes live on a website. Rather than being aimed at a single writer running the occasional free check, the platform is organized around team workflows: bulk scanning, shared reporting, scan history, and API access, so editorial teams can vet incoming content at scale before it gets published.$q$, $q$The core product runs two checks together on any piece of text: an AI-generated-content detector trained to recognize output from large language models such as GPT-4, GPT-4o, Claude, Gemini, and Llama, and a plagiarism scanner that compares the text against indexed web sources for matching passages. Around these two central checks, Originality.ai layers a readability score and a beta fact-checking feature that highlights specific factual claims worth a second look, giving editors a broader quality picture than a single AI-or-not verdict.$q$, $q$Access to the platform is entirely credit-based: every scan consumes credits tied to the word count being checked, and credits are obtained either through a monthly subscription plan (Pro or Enterprise) or a one-off pay-as-you-go purchase. New accounts receive a small allotment of free credits so they can trial the AI and plagiarism detectors before committing to a paid plan, though there is no ongoing free tier for regular, unlimited use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$who-originality-ai-is-for$q$, $q$Who Originality.ai Is For$q$, 2, ARRAY[$q$Originality.ai is built for teams that publish or commission written content at volume and need a consistent, auditable way to screen it before it goes live. Content agencies vetting freelance writers, in-house SEO and content teams protecting a site's editorial standards, and digital publishers managing many contributors are the clearest fit, since the platform's team seats, shared reports, and scan history are designed specifically around that kind of ongoing editorial oversight rather than a single one-time check.$q$, $q$It also suits organizations that want to combine AI detection with plagiarism checking in a single pass instead of running two separate tools, since one shared credit pool covers both checks together in the same report. Marketing teams producing large volumes of blog or landing-page copy, and any business relying on freelance or AI-assisted writers, can use the API to fold detection directly into an existing content pipeline or CMS.$q$, $q$Enterprise buyers who need audit trails, API integration, and role-based team management will find the higher-tier plans built with them specifically in mind, offering enough monthly credits and reporting depth to support a full editorial operation with multiple reviewers, rather than a single writer's occasional check on one document.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Casual bloggers or students who only need to check a single essay or post now and then may find Originality.ai's credit-based pricing and team-oriented features more than they need, especially since there is no lasting free plan to fall back on once the initial trial credits are used up.$q$, $q$Anyone expecting a definitive, courtroom-grade verdict on whether a piece of text was written by AI should also be cautious: like every AI detector currently on the market, Originality.ai's scores are probabilistic rather than absolute, and heavily edited or paraphrased AI text, as well as certain non-native English writing patterns, can occasionally produce false positives or false negatives that require human judgment to interpret correctly.$q$, $q$Very small teams or solo creators with tight budgets and only occasional scanning needs may find an ongoing subscription cost hard to justify next to a lighter, one-off plagiarism tool, particularly if features like API access, team dashboards, and long-term scan history audit trails aren't things they would actually use.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Originality.ai is its combined AI-and-plagiarism scan, which returns a single report showing the likelihood that a passage was AI-generated alongside any matched sources found across the web, so editors don't need to run two separate tools or reconcile two separate reports to get both answers.$q$, $q$A Chrome extension extends scanning into Google Docs and any webpage, letting writers and editors check content in context before it is copied elsewhere, while the fact-checking beta highlights specific factual claims in a draft that may be worth independently verifying, and a built-in readability score rounds out the overall content-quality picture in the same report.$q$, $q$For teams, shared dashboards, scan history, and role-based seats let managers see what has been checked and by whom, and the API lets developers wire AI and plagiarism checks directly into a CMS, content pipeline, or internal review tool instead of relying on manually pasting text into the dashboard one document at a time.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', $q$the-originality-ai-experience$q$, $q$The Originality.ai Experience$q$, 2, ARRAY[$q$Using Originality.ai typically starts with pasting text, uploading a document, or scanning a URL directly from the dashboard or the Chrome extension; results come back within seconds as a percentage score for AI-likely content plus a highlighted breakdown of any plagiarism matches found in the text.$q$, $q$The interface is built for repeat, workflow-style use rather than a single check: scan history stays available for the whole team to reference, reports can be shared with colleagues or clients without granting them full account access, and credits are tracked transparently against whichever monthly plan or pay-as-you-go balance is currently active.$q$, $q$Because the underlying detection models are updated as new AI writing tools emerge, using Originality.ai feels like ongoing recalibration rather than a static, one-time tool, which suits teams that need continuous editorial coverage well but is a heavier commitment than someone looking for a single free check and nothing more.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
