INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53bb6923-d4d1-4ead-bd6a-7aa8450e41ee', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Merchant of Record$q$, $q$Paddle becomes the legal seller of record, taking on responsibility for calculating, collecting, and remitting sales tax and VAT across jurisdictions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Hosted & Embedded Checkout$q$, $q$A customizable checkout available as an overlay, inline component, or hosted page, supporting cards, PayPal, and various local payment methods.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Subscription Billing$q$, $q$Plan management, proration, trials, upgrades and downgrades, and automated recurring invoicing for SaaS pricing models.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Dunning & Payment Recovery$q$, $q$Automated retry logic and communications for failed renewal payments, aimed at reducing involuntary churn.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Global Tax Compliance$q$, $q$Automatic sales tax and VAT calculation, collection, and remittance in supported countries, removing the need for direct tax registration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Multi-Currency & Localization$q$, $q$Automatic currency conversion and localized price display so international buyers see familiar currencies and formats at checkout.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Customer Portal$q$, $q$A self-serve portal where end customers can manage subscriptions, update payment details, and access invoices without contacting support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Reporting & Analytics$q$, $q$Dashboards covering revenue, subscription churn, and tax liability to help teams track the financial health of their software business.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$API & Webhooks$q$, $q$Programmatic access to checkout, subscription, and customer data, with webhook events for triggering app logic like access provisioning.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Invoicing$q$, $q$Automatically generated, compliant invoices and receipts suited to B2B buyers who need documentation for expense reporting.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Removes the burden of registering for and remitting sales tax and VAT across multiple countries$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Bundles checkout, subscription billing, invoicing, and dunning into a single integration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Supports many currencies and localized payment methods for international selling$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Self-serve customer portal reduces billing-related support requests$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Well suited to solo founders and small teams without dedicated finance or legal staff$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Bundled per-transaction pricing can be more expensive than assembling a custom stack at high volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Less direct control over checkout design and payment flow compared to a raw payment gateway$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Primarily oriented toward digital software and SaaS, not physical goods or marketplaces$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Switching away from a merchant-of-record model later can require significant rework$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Some advanced or highly custom billing scenarios may not fit Paddle's standardized flows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$What does it mean that Paddle is a merchant of record?$q$, $q$As merchant of record, Paddle is the legal seller in every transaction, which means it takes on responsibility for calculating, collecting, and remitting sales tax and VAT, rather than leaving that compliance work to the software company selling the product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$How is Paddle's pricing structured?$q$, $q$Paddle charges a percentage plus a fixed fee per transaction rather than a monthly subscription fee, so costs scale with usage. Businesses with high volume or unique needs can also discuss custom pricing directly with Paddle.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Does Paddle work for physical products or only software?$q$, $q$Paddle is built primarily for digital software and SaaS products. Businesses selling physical goods or operating complex marketplaces are typically better served by other payment platforms.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$How does Paddle compare to using Stripe directly?$q$, $q$Stripe is a payment processor that moves money but leaves tax compliance and liability with the seller. Paddle bundles payment processing with merchant-of-record tax handling, subscription billing, and invoicing, at a higher per-transaction cost in exchange for taking on that compliance burden.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Can customers manage their own subscriptions?$q$, $q$Yes. Paddle provides a self-serve customer portal where buyers can update payment methods, view invoices, and manage or cancel their subscriptions without contacting the seller's support team.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Launching a subscription SaaS product globally$q$, $q$A software company can set up recurring billing, checkout, and international tax handling in one integration instead of building compliance infrastructure from scratch.$q$, $q$SaaS founders and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Selling software without a dedicated finance or legal team$q$, $q$Solo developers and small teams can accept payments worldwide while Paddle manages tax registration, calculation, and remittance on their behalf.$q$, $q$Indie developers and small software businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Reducing churn from failed payments$q$, $q$Growing subscription businesses use Paddle's automated dunning and payment recovery workflows to retry failed renewals and cut down on involuntary cancellations.$q$, $q$SaaS teams focused on retention$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Expanding into new international markets$q$, $q$Companies entering new countries use Paddle to handle local payment methods, currency conversion, and region-specific tax rules without separate local registrations.$q$, $q$Scaling software companies going international$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Standard$q$, $q$5% + $0.50 per transaction$q$, $q$Per transaction, no monthly fee$q$, $q$["Merchant-of-record tax handling","Hosted and embedded checkout","Subscription billing and invoicing","Dunning and payment recovery","Customer portal access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$Custom / High Volume$q$, $q$Custom pricing$q$, $q$Negotiated per contract$q$, $q$["Volume-based transaction rates","Dedicated account support","Advanced reporting and analytics","Tailored contract terms for larger businesses"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Paddle is a payments infrastructure company founded in 2012 and headquartered in London, built around a single idea: software companies should not have to become payments and tax experts just to sell online. Instead of offering a raw payment gateway, Paddle acts as a merchant of record, meaning it legally sells on behalf of its customers, taking on the responsibility for calculating, collecting, and remitting sales tax and VAT in every jurisdiction where a sale happens.$q$, $q$In practice this means a SaaS company can plug in Paddle's checkout, connect it to subscription plans, and immediately start billing customers around the world without registering for tax in dozens of countries or negotiating separately with card networks, PayPal, and other payment methods. Paddle handles currency conversion, localized pricing, invoicing, dunning for failed payments, and refunds, all from one dashboard and API.$q$, $q$This positions Paddle differently from traditional payment processors like Stripe or Braintree, which move money but leave tax liability, compliance, and much of the billing logic to the merchant. Paddle's trade-off is a bundled, higher per-transaction fee in exchange for taking that operational and legal burden off the software company's plate, which is why it is most often compared not to a payment gateway but to an outsourced billing and compliance department.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$who-paddle-is-for$q$, $q$Who Paddle Is For$q$, 2, ARRAY[$q$Paddle is built for software and SaaS businesses that sell internationally and want to avoid the overhead of tax registration, VAT filings, and multi-currency payment logistics. Teams without an in-house finance or legal function often turn to Paddle specifically because it removes the need to track changing tax rules across the US, EU, UK, and other regions.$q$, $q$Solo founders, indie developers, and small teams shipping a subscription product benefit from Paddle's all-in-one approach, since it bundles checkout, recurring billing, invoicing, and customer-facing subscription management into a single integration rather than requiring separate tools stitched together with custom code.$q$, $q$Growing SaaS companies that are starting to sell in new countries, or that have been burned by unexpected tax exposure, also gravitate toward Paddle because the merchant-of-record model shifts that specific risk onto Paddle. It suits companies that would rather pay a bundled fee for peace of mind than manage compliance internally as they scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses with very high transaction volumes and dedicated finance and tax teams may find Paddle's bundled percentage-based fee more expensive than assembling a lower-cost stack of a payment processor plus a separate tax automation tool, especially once volume discounts and negotiated interchange rates come into play.$q$, $q$Paddle is oriented toward digital software and SaaS products, so companies selling physical goods, running marketplaces with complex multi-party payouts, or operating in industries with unusual payment flows are generally better served by more general-purpose or industry-specific payment platforms.$q$, $q$Teams that need deep, pixel-level control over the checkout experience, highly custom payment flows, or the flexibility to swap processors and negotiate rates directly may also find the merchant-of-record model restrictive, since Paddle standardizes much of the checkout and billing logic in exchange for handling compliance.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Paddle is its checkout, available as an overlay, inline embed, or hosted page, supporting major cards, PayPal, and a range of local payment methods along with automatic currency conversion and localized pricing display, so buyers see prices and pay in ways that feel native to their region.$q$, $q$On top of checkout sits subscription billing: plan and pricing management, proration, trials, upgrades and downgrades, automated dunning for failed renewal payments, and tools aimed at recovering and reducing churn. Paddle also generates compliant invoices and receipts automatically, which matters for B2B buyers who need proper documentation for expensing software purchases.$q$, $q$Because Paddle is the merchant of record, it calculates and remits sales tax and VAT on every transaction, removing the need for sellers to register in each tax jurisdiction. This is backed by reporting and analytics on revenue, churn, and tax liability, along with an API and webhooks so engineering teams can trigger custom logic, like provisioning access, whenever a subscription event occurs.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', $q$the-paddle-experience$q$, $q$The Paddle Experience$q$, 2, ARRAY[$q$Getting started with Paddle typically involves setting up a seller account, configuring products and prices in the dashboard, and embedding Paddle's checkout on a marketing site or in-app upgrade flow. Because Paddle handles the tax and payment method complexity behind the scenes, the initial integration is often faster than assembling an equivalent stack from separate billing and tax tools.$q$, $q$Day to day, founders and finance teams work primarily out of the Paddle dashboard to monitor subscriptions, revenue, and failed payments, while customers manage their own subscriptions, payment methods, and invoices through a self-serve customer portal, which reduces support tickets around billing questions.$q$, $q$The experience does come with some loss of direct control, since sellers rely on Paddle's checkout UI, supported payment methods, and release cadence rather than building everything bespoke. Most users describe the trade-off as favorable once they weigh it against the time and legal risk of handling global tax compliance and multi-currency billing themselves.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e2b1c07-9d70-4dd3-a9e0-b4a7473ba11f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Document-style form editor$q$, $q$Build forms by writing free-flowing text, headings, and images alongside question fields, rather than filling in a rigid field grid.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Conditional logic$q$, $q$Show or hide questions and sections dynamically based on earlier responses to create branching, personalized forms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Payments and calculators$q$, $q$Accept payments via Stripe or PayPal and build pricing or quantity calculators so forms can function as order pages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Templates library$q$, $q$Start from ready-made templates for surveys, registrations, applications, bookings, and simple online stores.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$E-signatures and file uploads$q$, $q$Collect signed agreements and uploaded files directly within a form submission.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Custom branding and design$q$, $q$Adjust fonts, colors, images, and layout so published forms match a company's visual identity.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Integrations and automation$q$, $q$Connect to Zapier, Google Sheets, Mailchimp, and popular CRMs to route submission data into existing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Submission and response management$q$, $q$Review, filter, and export responses, with notifications when new submissions come in.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Custom domains and embedding$q$, $q$Publish forms on a custom domain or embed them directly into an existing website.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Document-style editor makes forms feel like branded pages rather than generic surveys$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Strong built-in commerce tools, including payments and pricing calculators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Extensive design customization for matching brand identity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Template library speeds up creation for common use cases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Conditional logic enables sophisticated, branching forms without coding$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$No permanent free plan, only a limited trial period$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$May be more form builder than needed for very simple, occasional use cases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Advanced enterprise governance or workflow features are limited compared to enterprise-focused platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Deep custom logic beyond built-in options requires relying on third-party integrations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Pricing can feel steep for solo users compared to lightweight free alternatives$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Does Paperform offer a free plan?$q$, $q$Paperform does not offer a permanent free plan; instead it provides a free trial period so users can test paid features before subscribing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Can Paperform accept payments?$q$, $q$Yes, Paperform integrates with providers like Stripe and PayPal so forms can collect payments, including for orders with calculated pricing or quantities.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Is Paperform good for non-technical users?$q$, $q$Yes, its document-style editor is designed to be approachable for people without coding experience, letting them build polished forms visually.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$What can Paperform be used for besides basic forms?$q$, $q$Beyond simple data collection, it's commonly used for surveys, quizzes, event registrations, client intake, bookings, and lightweight e-commerce order pages.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Does Paperform integrate with other tools?$q$, $q$Yes, it connects with services such as Zapier, Google Sheets, Mailchimp, and various CRMs to pass submission data into other systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Service booking and order forms$q$, $q$Combine service selection, pricing calculators, and payment collection into a single branded form for booking appointments or ordering products.$q$, $q$Small business owners and service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Client intake and onboarding$q$, $q$Gather structured client information, files, and signed agreements through a form that feels like part of the company's own site.$q$, $q$Consultants, coaches, and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Event registration$q$, $q$Create registration pages with conditional questions, payment for tickets, and confirmation messaging tailored to attendee responses.$q$, $q$Event organizers and community groups$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Surveys and quizzes$q$, $q$Build branching surveys or scored quizzes that adapt questions based on prior answers to gather more relevant feedback or leads.$q$, $q$Marketers and researchers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Essentials$q$, $q$From approximately $24/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Unlimited forms","Core payment collection","Basic integrations","Template library access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Pro$q$, $q$Mid-tier pricing above Essentials$q$, $q$Monthly or annual$q$, $q$["Advanced calculations","More integrations","Higher submission and response limits","Additional branding controls"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Business$q$, $q$Higher-tier pricing above Pro$q$, $q$Monthly or annual$q$, $q$["Team collaboration features","Priority support","Expanded automation options","Advanced customization"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$Agency / Custom$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Higher volume needs","Multi-client management","Dedicated support","Custom requirements"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Paperform is a web-based form, survey, and landing page builder founded in Melbourne, Australia, in 2015. Rather than presenting users with a rigid grid of fields, Paperform treats a form like a document: you type text, headings, and images in a flowing editor, then drop in fields, payment blocks, or calculators wherever they belong. The result reads more like a branded page than a typical utilitarian form.$q$, $q$The platform is aimed at people who want forms that double as marketing assets. Beyond basic data collection, Paperform supports conditional logic, pricing and quantity calculators, file uploads, e-signatures, and native payment collection through providers such as Stripe and PayPal. This lets a single form act as an order page, booking flow, application, or survey without needing a separate checkout tool.$q$, $q$Templates cover common use cases like event registration, client intake, feedback surveys, and simple online stores, which shortens the path from idea to a published form. Integrations with tools like Zapier, Google Sheets, Mailchimp, and various CRMs extend what happens after a submission is collected, so responses can flow into a business's existing workflow rather than sitting isolated in a dashboard.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$who-paperform-is-for$q$, $q$Who Paperform Is For$q$, 2, ARRAY[$q$Paperform suits small business owners, freelancers, coaches, and consultants who need professional-looking forms without hiring a developer. Its document-style editor is approachable for non-technical users who want to control layout, copy, and branding closely, rather than settling for a generic field-by-field form template that looks like every other survey tool on the market.$q$, $q$It's a strong fit for anyone selling services or products directly through a form, since built-in payment collection, order calculators, and conditional pricing let a form function as a lightweight storefront or booking page. Event organizers, tutors, and service providers who need to combine information gathering with payment in a single step often gravitate toward it.$q$, $q$Marketing-minded teams that want forms to reinforce brand identity also benefit, since Paperform's design controls go further than most competitors, allowing custom fonts, colors, and imagery. Small agencies building forms or landing pages on behalf of clients can use the flexible design system to match each client's look without starting from scratch every time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex approval workflows, multi-department form governance, or the need for deep native integration with enterprise systems may find Paperform's feature set narrower than dedicated enterprise forms or workflow-automation platforms. Organizations with strict, specific compliance or data-residency requirements should verify those needs directly with Paperform before committing.$q$, $q$Teams that want a permanently free plan should look elsewhere, since Paperform is built around paid subscription tiers with a trial period rather than an indefinitely free tier. Budget-constrained hobbyists or occasional users who only need to publish an occasional simple form may find the pricing hard to justify compared to lighter, free form tools.$q$, $q$Developers who need extensive, code-level customization of form logic, or businesses requiring a form builder deeply embedded inside a broader product suite (like an all-in-one CRM or help desk platform), may prefer a more specialized or developer-first tool instead of a standalone form and landing page builder like Paperform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Paperform is its document-style editor, which lets users write a form the way they'd write a page, interleaving narrative text, images, and questions freely. This is paired with conditional logic so that later questions or sections can appear or hide based on earlier answers, letting a single form branch into different paths for different respondents.$q$, $q$Commerce features are a standout: forms can include product selection, quantity and pricing calculators, coupon codes, and checkout via Stripe or PayPal, turning a form into a functional order page. Additional capabilities include e-signature collection, file uploads, scheduling integrations, and quiz-style scoring, which broadens use beyond simple lead capture into surveys, applications, and bookings.$q$, $q$On the operational side, Paperform provides submission management, response notifications, spreadsheet-style data views, and integrations with tools such as Zapier, Google Sheets, Mailchimp, and popular CRMs. Custom domains, embeddable forms, and branding controls round out the feature set, letting published forms sit comfortably on a company's own website or as a standalone branded page.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b3f994ed-6c32-4065-b748-3f9cadf0652e', $q$the-paperform-experience$q$, $q$The Paperform Experience$q$, 2, ARRAY[$q$Using Paperform feels closer to writing in a document editor than configuring a traditional form builder. New users typically start from a template or a blank page, then add text and question blocks in whatever order makes sense, with a live preview showing exactly how respondents will see the finished form as it's built.$q$, $q$The interface keeps advanced options, like conditional logic, calculations, and payment settings, accessible without cluttering the main writing canvas, so day-to-day editing stays uncluttered even as forms grow more sophisticated. This balance helps non-technical users build reasonably complex forms without feeling like they've stepped into a developer tool.$q$, $q$Published forms are responsive by default and render cleanly on mobile devices, which matters since a meaningful share of form traffic arrives from phones. Overall, the experience is designed to make a form feel like part of a brand's website rather than an obviously bolted-on third-party widget, which is a key part of Paperform's appeal.$q$]::text[], 4);
