INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f5ec638-3b36-43dd-9893-d9d2465f2931', $q$Automated payroll processing$q$, $q$Runs payroll on flexible schedules, calculating wages, deductions, and garnishments across salaried, hourly, and tipped employees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f5ec638-3b36-43dd-9893-d9d2465f2931', $q$Payroll tax administration$q$, $q$Calculates, files, and remits federal, state, and local payroll taxes on the employer's behalf and prepares year-end tax forms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f5ec638-3b36-43dd-9893-d9d2465f2931', $q$Employee self-service portal$q$, $q$Lets employees view pay stubs, tax documents, and benefits, and update personal information without contacting HR directly.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f5ec638-3b36-43dd-9893-d9d2465f2931', $q$Benefits administration$q$, $q$Supports enrollment and management of health benefits and integrates with retirement plan providers.$q$, 3);
