INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f5ec638-3b36-43dd-9893-d9d2465f2931', $q$Hiring and onboarding tools$q$, $q$Applicant tracking and new-hire onboarding workflows to move candidates from offer to first paycheck.$q$, 5);
